+fn run_microbench(mode: SafetyLevel, cfg: MicrobenchConfig) -> KernelBenchSuite {
+    let decide = bench_decide(mode, cfg);
+    let decide_observe = bench_decide_observe(mode, cfg);
+    KernelBenchSuite {
+        decide,
+        decide_observe,
+    }
+}
